mapper.insert:
INSERT INTO UNTACT_BOOK_BLACKLIST
(
 	homepage_id, member_id, member_name, penalty_reason, penalty_day,
 	penalty_register_ip, penalty_register_id
) VALUES
(
	#{homepage_id}, #{member_id}, #{member_name}, #{penalty_reason}, TO_DATE(#{penalty_day},'yyyy-MM-dd HH24:MI:SS'),
	#{penalty_register_ip}, #{penalty_register_id}
)

mapper.select:
${pagingTop}
	SELECT
		homepage_id, member_id, member_name, penalty_reason, TO_CHAR(penalty_day,'yyyy-MM-dd HH24:MI:SS') AS penalty_day,
	 	penalty_register_ip, penalty_register_id
	FROM
		UNTACT_BOOK_BLACKLIST
	WHERE
		homepage_id = #{homepage_id}

	ORDER BY penalty_day DESC
${pagingBottom}

mapper.delete:
DELETE FROM UNTACT_BOOK_BLACKLIST
WHERE
	homepage_id = #{homepage_id}
AND member_id = #{member_id}
